var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"나는 가족을 갖고 싶었어.","JPN":"私は家族がほしかったの。","ENG":"I've always wanted a family.","TWN":"我想要擁有家人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"태어나자마자 불량품이라고 부르거나, 세상에서 지워 버리려고 하지 않는......","JPN":"生まれてすぐに不良品って呼んできたり、世の中から消してしまおうとしない……","ENG":"Not like the ones from that cursed organization, who call you a defect as soon as you're born or try to remove you from existence...","TWN":"不會一出生就叫我瑕疵品，或是想把我從這個世界上抹殺掉……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"그런 가족들 말이야.","JPN":"そういう家族が。","ENG":"I mean a real family.","TWN":"我想要擁有那樣的家人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"후훗, 기쁜 자리인데 내가 너무 울적한 얘기를 꺼내 버렸나?","JPN":"ふふっ、嬉しい場面なのに、暗い話をしちゃったみたいね。","ENG":"Heh, did I just throw a wet blanket on this cheerful occasion?","TWN":"呵呵，明明是令人開心的場合，我卻說出了沉重的話？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"작은 심술이라고 생각해. 그러게 자기 방을 어지럽히고 안 치우면 못쓰지.","JPN":"ちょっとした意地悪だと思って。だってあなた、いつも自分の部屋を散らかしっぱなしなんだもの。","ENG":"Just think of this as my little tantrum. You ought to keep your room clean, you know.","TWN":"這是我小小的惡作劇。弄亂了自己的房間，不收拾可不行。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"사실 나야 매일 일거리를 만들어 줘서 고맙지만.","JPN":"私にとっては、仕事を作ってくれてありがたいけど。","ENG":"Though to be honest, I appreciate the daily work.","TWN":"其實，我很感謝你每天都幫我找事情做。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"나랑 같이 만들어졌던 애들은 너무 자기 할일에만 충실했거든.","JPN":"私と一緒に作られた子たちは、自分のやることにだけ、忠実だったから。","ENG":"All other clones from my batch were so committed to their jobs, but that was it.","TWN":"因為跟我一起製造出來的那些朋友，全都太專注於自己的工作了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"기껏 한가한 날에도 하루 내내 총칼만 닦고 있질 않나, 운동만 하지 않나. 뭘 그렇게 열심히 하고 싶은지.","JPN":"せっかく暇な日ができても、一日中武器を磨いたり、運動ばかりして。なにをそんなに頑張っているのかしらね。","ENG":"They'd be polishing their weapons or working out all day, even on the easy days. I don't know why they were hell bent on doing so well.","TWN":"好不容易清閒的日子，整天不是擦刀槍，就是不斷做運動。真不知道這麼拼命是想做什麼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"다 같이 웃고 떠들 순간을 남기기에도 시간이 모자란데 말이야.","JPN":"みんなで笑ったり、おしゃべりしながら思い出を作る時間すらないのに。","ENG":"There's hardly enough time to laugh, joke, and play as it is.","TWN":"大家一起大笑大鬧的時間明明剩沒多少了啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"모르겠어. 주말마다 모여서 나들이라도 나갔으면 더 좋았으려나......","JPN":"わからない。週末にはみんなで集まって、遊びにでも出かけてたら良かったのかしら……","ENG":"I don't know... Maybe it would've been better if we went on picnics together on the weekends...","TWN":"我不知道，是不是每個週末都一起出去玩會更比較好呢……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"난 말이야, 여기가 매일 시끌벅적하고 바람 잘 날 없는 곳이면 좋겠어.","JPN":"私ね、ここは毎日賑やかで騒がしいところになってほしいの。","ENG":"You know, I hope this place always stays loud and somewhat chaotic.","TWN":"我啊，希望這裡每天都熱熱鬧鬧、無憂無慮的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"당신이라면 그렇게 해 줄 수 있겠지?","JPN":"あなたなら、そうしてくれるよね？","ENG":"You can keep it that way, right?","TWN":"是你的話，應該可以做到吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_ReinforcedB_NULL","text":{"KOREA":"앞으로도 오래...... 조금이라도 괜찮으니까 더 오랫동안.","JPN":"これからもずっと……少しでもいいから長い間。","ENG":"I want this to last longer... It doesn't have to be forever, but just a little longer.","TWN":"之後也長久地……哪怕只是多一點點也好，讓這種日子能更長久地持續下去。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_ReinforcedB_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};